using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public sealed class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public sealed class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

public sealed class PredictRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public sealed class PredictResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Probabilities { get; set; } = new();
}

public sealed class TrainResponse
{
    public string Message { get; set; } = string.Empty;
    public EvaluationMetrics Metrics { get; set; } = new();
}

public sealed class EvaluationMetrics
{
    public float MacroAccuracy { get; set; }
    public float MicroAccuracy { get; set; }
    public float LogLoss { get; set; }
    public float LogLossReduction { get; set; }
    public List<CategoryMetric> PerCategory { get; set; } = [];
}

public sealed class CategoryMetric
{
    public string Category { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly string _dataPath;
    private readonly string _modelPath;
    private ITransformer? _model;
    private PredictionEngine<TicketInput, TicketPrediction>? _predictionEngine;
    private readonly string[] _categories = ["Billing", "Technical", "General"];
    private readonly Lock _lock = new();

    public bool IsModelTrained => _model is not null;

    public TicketClassifierService(IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public EvaluationMetrics TrainAndEvaluate()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // With a small dataset, train on all data and evaluate on training set
        // to demonstrate metrics. In production, use cross-validation or a split.
        var model = pipeline.Fit(data);
        var predictions = model.Transform(data);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        lock (_lock)
        {
            _model = model;
            _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketInput, TicketPrediction>(model);
        }

        _mlContext.Model.Save(model, data.Schema, _modelPath);

        var confusionMatrix = metrics.ConfusionMatrix;
        var perCategory = new List<CategoryMetric>();
        for (int i = 0; i < confusionMatrix.PerClassPrecision.Count && i < _categories.Length; i++)
        {
            perCategory.Add(new CategoryMetric
            {
                Category = _categories[i],
                Precision = confusionMatrix.PerClassPrecision[i],
                Recall = confusionMatrix.PerClassRecall[i],
                F1Score = 2 * confusionMatrix.PerClassPrecision[i] * confusionMatrix.PerClassRecall[i]
                    / (confusionMatrix.PerClassPrecision[i] + confusionMatrix.PerClassRecall[i] + 1e-10),
            });
        }

        return new EvaluationMetrics
        {
            MacroAccuracy = (float)metrics.MacroAccuracy,
            MicroAccuracy = (float)metrics.MicroAccuracy,
            LogLoss = (float)metrics.LogLoss,
            LogLossReduction = (float)metrics.LogLossReduction,
            PerCategory = perCategory,
        };
    }

    public PredictResponse Predict(PredictRequest request)
    {
        PredictionEngine<TicketInput, TicketPrediction> engine;
        lock (_lock)
        {
            engine = _predictionEngine
                ?? throw new InvalidOperationException("Model has not been trained. POST /api/tickets/train first.");
        }

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        TicketPrediction prediction;
        lock (_lock)
        {
            prediction = engine.Predict(input);
        }

        var probabilities = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < _categories.Length; i++)
        {
            probabilities[_categories[i]] = prediction.Score[i];
        }

        return new PredictResponse
        {
            PredictedCategory = prediction.Category,
            Probabilities = probabilities,
        };
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public sealed class TicketsController(TicketClassifierService classifier) : ControllerBase
{
    [HttpPost("train")]
    public ActionResult<TrainResponse> Train()
    {
        var metrics = classifier.TrainAndEvaluate();
        return Ok(new TrainResponse
        {
            Message = "Model trained successfully",
            Metrics = metrics,
        });
    }

    [HttpPost("predict")]
    public ActionResult<PredictResponse> Predict([FromBody] PredictRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        if (!classifier.IsModelTrained)
            return BadRequest("Model has not been trained. POST /api/tickets/train first.");

        var result = classifier.Predict(request);
        return Ok(result);
    }
}

